import * as React from "react";

export interface ScreenCandidateStepProps {
	instanceId: string;
	state: string;
	onEvent: (event: string, payload?: Record<string, unknown>) => Promise<void> | void;
}

const FIELDS: ReadonlyArray<{ id: string; label: string; required: boolean; pii: boolean }> = [
	{ id: "screen_score", label: "Screen score (1-5)", required: true, pii: false },
	{ id: "screen_notes", label: "Screen notes", required: true, pii: false },
	{ id: "years_exp", label: "Years experience", required: true, pii: false },
	{ id: "salary_expect", label: "Salary expectation", required: false, pii: false },
	{ id: "availability", label: "Available from", required: false, pii: false },
];

/**
 * Minimal review step for the screen_candidate workflow. Hosts wrap this with
 * the project-wide auth/tenant context — keeping the component dumb so
 * generated code stays portable across Next.js and plain Vite apps.
 */
export function ScreenCandidateStep(props: ScreenCandidateStepProps): React.ReactElement {
	const [busy, setBusy] = React.useState(false);

	const fire = React.useCallback(
		async (event: string) => {
			if (busy) return;
			setBusy(true);
			try {
				await props.onEvent(event, {});
			} finally {
				setBusy(false);
			}
		},
		[busy, props],
	);

	return (
		<section data-testid="screen_candidate-step" aria-labelledby="screen_candidate-step-title">
			<header>
				<h2 id="screen_candidate-step-title">Screen a candidate</h2>
				<p>State: <code>{props.state}</code></p>
				<p>Instance: <code>{props.instanceId}</code></p>
			</header>
			<dl>
				{FIELDS.map((field) => (
					<React.Fragment key={field.id}>
						<dt>{field.label}{field.required ? " *" : ""}{field.pii ? " (PII)" : ""}</dt>
						<dd>—</dd>
					</React.Fragment>
				))}
			</dl>
			<footer>
				<button type="button" disabled={busy} onClick={() => fire("submit")}>
					Submit
				</button>
				<button type="button" disabled={busy} onClick={() => fire("approve")}>
					Approve
				</button>
			</footer>
		</section>
	);
}
